mapper.select:
SELECT a.id AS personalTagsCategoryId, c.category_name, b.* FROM store_personal_tag_category a LEFT JOIN store_personal_tags b ON a.tag_id = b.id LEFT JOIN kol_tag_category c ON a.category_id = c.id WHERE a.category_id = #{storePersonalTagsModel.categoryId}
and b.tag_name like CONCAT('%', #{storePersonalTagsModel.tagName}, '%')
and a.del_flag = #{storePersonalTagsModel.delFlag}
